export function parseCsv(text, options = {}) {
  // TODO: replace with a robust parser
  const lines = text.trim().split(/\r?\n/).filter(Boolean);
  const headers = lines[0].split(',').map(s => s.trim());
  const rows = lines.slice(1).map(line => Object.fromEntries(line.split(',').map((cell, i) => [headers[i], cell.trim()])));
  return { headers, rows, warnings: [] };
}

export function profileCsv(text, options = {}) {
  const parsed = parseCsv(text, options);
  return {
    ...parsed,
    columns: {},
    issues: [],
    suggestions: []
  };
}

