import test from 'node:test';
import assert from 'node:assert/strict';
import { parseCsv, profileCsv } from './profiler.js';

test('parses quoted commas, escaped quotes, comments, and blank lines', () => {
  const csv = '# generated by legacy export\n\nid,name,notes\n1,"Ada, Lovelace","said ""hello"""\n2,Bob,plain\n';
  const parsed = parseCsv(csv, { comments: true });
  assert.deepEqual(parsed.headers, ['id', 'name', 'notes']);
  assert.equal(parsed.rows[0].name, 'Ada, Lovelace');
  assert.equal(parsed.rows[0].notes, 'said "hello"');
  assert.equal(parsed.rows.length, 2);
});

test('profiles basic column statistics and inferred types', () => {
  const csv = 'id,created_at,amount,email\n1,2026-01-01,12.50,a@example.com\n2,2026-01-03,,bad-email\n3,not-a-date,7.25,c@example.com\n';
  const result = profileCsv(csv, { required: ['id', 'created_at'], primaryKey: 'id' });
  assert.equal(result.columns.id.distinct, 3);
  assert.equal(result.columns.amount.nulls, 1);
  assert.equal(result.columns.amount.type, 'number');
  assert.equal(result.issues.some(i => i.type === 'invalid_date' && i.column === 'created_at'), true);
});

test('detects duplicate primary keys and inconsistent row widths with suggestions', () => {
  const csv = 'id,name\n1,Ada\n1,Ada Duplicate\n2\n3,Charlie,extra\n';
  const result = profileCsv(csv, { primaryKey: 'id' });
  assert.equal(result.issues.some(i => i.type === 'duplicate_primary_key'), true);
  assert.equal(result.issues.some(i => i.type === 'row_width_mismatch'), true);
  assert.equal(result.suggestions.length > 0, true);
  assert.equal(result.suggestions.every(s => typeof s.message === 'string' && s.message.length > 0), true);
});
